    def __init__(self):
        self.boards = [Board() for _ in range(3)]
        self.tetrominos = [Tetromino() for _ in range(3)]
        self.current_player = 0
        self.running = True

    def switch_player(self):
        self.current_player = (self.current_player + 1) % 3

    def update(self):
        # Game logic to move tetromino down and check for collisions
        pass

    def draw(self, screen):
        for i, board in enumerate(self.boards):
            for y, row in enumerate(board.grid):
                for x, value in enumerate(row):
                    if value:
                        pygame.draw.rect(screen, value, (x * GRID_SIZE + i * (BOARD_WIDTH * GRID_SIZE + 20), y * GRID_SIZE, GRID_SIZE, GRID_SIZE))
            score_text = pygame.font.SysFont('Arial', 24).render(f'Player {i + 1} Score: {board.score}', True, (255, 255, 255))
