import pygame
import random

# Constants
SCREEN_WIDTH = 800
SCREEN_HEIGHT = 600
BLOCK_SIZE = 30
BOARD_WIDTH = 10
BOARD_HEIGHT = 20
FPS = 60

# Colors
COLORS = [
    (0, 0, 0),  # Black
    (255, 0, 0),  # Red
    (0, 255, 0),  # Green
    (0, 0, 255),  # Blue
    (255, 255, 0),  # Yellow
    (255, 165, 0),  # Orange
    (128, 0, 128),  # Purple
    (0, 255, 255)   # Cyan
]

class Tetromino:
    shapes = [
        [[1, 1, 1, 1]],  # I
        [[1, 1], [1, 1]],  # O
        [[0, 1, 0], [1, 1, 1]],  # T
        [[1, 1, 0], [0, 1, 1]],  # S
        [[0, 1, 1], [1, 1, 0]],  # Z
        [[1, 0, 0], [1, 1, 1]],  # L
        [[0, 0, 1], [1, 1, 1]]   # J
    ]

    def __init__(self):
        self.shape = random.choice(self.shapes)
        self.color = random.randint(1, len(COLORS) - 1)
        self.x = BOARD_WIDTH // 2 - len(self.shape[0]) // 2
        self.y = 0

    def rotate(self):
        self.shape = [list(row) for row in zip(*self.shape[::-1])]

class Board:
    def __init__(self):
        self.grid = [[0 for _ in range(BOARD_WIDTH)] for _ in range(BOARD_HEIGHT)]
        self.score = 0

    def clear_lines(self):
        lines_to_clear = [i for i, row in enumerate(self.grid) if all(row)]
        for i in lines_to_clear:
            del self.grid[i]
            self.grid.insert(0, [0 for _ in range(BOARD_WIDTH)])
        self.score += len(lines_to_clear)

    def add_tetromino(self, tetromino):
        for y, row in enumerate(tetromino.shape):
            for x, value in enumerate(row):
                if value:
                    self.grid[tetromino.y + y][tetromino.x + x] = tetromino.color

class Player:
    def __init__(self, player_id):
        self.board = Board()
        self.tetromino = Tetromino()
        self.player_id = player_id

    def drop_tetromino(self):
        self.tetromino.y += 1
        if self.check_collision():
            self.tetromino.y -= 1
            self.board.add_tetromino(self.tetromino)
            self.tetromino = Tetromino()
            self.board.clear_lines()

    def check_collision(self):
        for y, row in enumerate(self.tetromino.shape):
            for x, value in enumerate(row):
                if value:
                    if (self.tetromino.x + x < 0 or
                        self.tetromino.x + x >= BOARD_WIDTH or
                        self.tetromino.y + y >= BOARD_HEIGHT or
                        self.board.grid[self.tetromino.y + y][self.tetromino.x + x]):
                        return True
        return False

class Game:
    def __init__(self):
        pygame.init()
        self.screen = pygame.display.set_mode((SCREEN_WIDTH, SCREEN_HEIGHT))
        self.players = [Player(i) for i in range(3)]
        self.clock = pygame.time.Clock()
        self.running = True

    def run(self):
        while self.running:
            self.handle_events()
            self.update()
            self.draw()
            self.clock.tick(FPS)

    def handle_events(self):
        for event in pygame.event.get():
            if event.type == pygame.QUIT:
                self.running = False

    def update(self):
        for player in self.players:
            player.drop_tetromino()

    def draw(self):
        self.screen.fill((255, 255, 255))
        for player in self.players:
            self.draw_board(player.board)
        pygame.display.flip()

    def draw_board(self, board):
        for y, row in enumerate(board.grid):
            for x, value in enumerate(row):
                if value:
                    pygame.draw.rect(self.screen, COLORS[value], (x * BLOCK_SIZE, y * BLOCK_SIZE, BLOCK_SIZE, BLOCK_SIZE))

if __name__ == "__main__":
    game = Game()
    game.run()
    pygame.quit()

