import random

# Constants
SCREEN_WIDTH = 800
SCREEN_HEIGHT = 600
GRID_SIZE = 30
GRID_WIDTH = SCREEN_WIDTH // GRID_SIZE
GRID_HEIGHT = SCREEN_HEIGHT // GRID_SIZE
FPS = 10

# Colors
COLORS = [
    (0, 0, 0), (255, 0, 0), (0, 255, 0), (0, 0, 255),
    (255, 255, 0), (255, 165, 0), (128, 0, 128), (0, 255, 255)
]

# Tetromino shapes
SHAPES = [
    [[1, 1, 1, 1]],  # I
    [[1, 1], [1, 1]],  # O
    [[0, 1, 0], [1, 1, 1]],  # T
    [[1, 1, 0], [0, 1, 1]],  # S
    [[0, 1, 1], [1, 1, 0]],  # Z
    [[1, 0, 0], [1, 1, 1]],  # L
    [[0, 0, 1], [1, 1, 1]]   # J
]

class Tetromino:
    def __init__(self):
        self.shape = random.choice(SHAPES)
        self.color = random.choice(COLORS)
        self.x = GRID_WIDTH // 2 - len(self.shape[0]) // 2
        self.y = 0

    def rotate(self):
        self.shape = [list(row) for row in zip(*self.shape[::-1])]

class Game:
    def __init__(self):
        self.board = [[0] * GRID_WIDTH for _ in range(GRID_HEIGHT)]
        self.current_tetromino = Tetromino()
        self.score = [0, 0, 0]
        self.player_turn = 0

    def valid_position(self, shape, offset_x, offset_y):
        for y, row in enumerate(shape):
            for x, cell in enumerate(row):
                if cell:
                    if (x + offset_x < 0 or x + offset_x >= GRID_WIDTH or
                            y + offset_y >= GRID_HEIGHT or
                            self.board[y + offset_y][x + offset_x]):
                        return False
        return True

    def merge_tetromino(self):
        for y, row in enumerate(self.current_tetromino.shape):
            for x, cell in enumerate(row):
                if cell:
                    self.board[y + self.current_tetromino.y][x + self.current_tetromino.x] = self.current_tetromino.color
        self.clear_lines()

    def clear_lines(self):
        lines_cleared = 0
        for y in range(GRID_HEIGHT):
            if all(self.board[y]):
                lines_cleared += 1
                del self.board[y]
                self.board.insert(0, [0] * GRID_WIDTH)
        self.score[self.player_turn] += lines_cleared * 100

    def switch_player(self):
        self.player_turn = (self.player_turn + 1) % 3

    def drop_tetromino(self):
        if self.valid_position(self.current_tetromino.shape, self.current_tetromino.x, self.current_tetromino.y + 1):
            self.current_tetromino.y += 1
        else:
            self.merge_tetromino()
            self.current_tetromino = Tetromino()
            if not self.valid_position(self.current_tetromino.shape, self.current_tetromino.x, self.current_tetromino.y):
