# Colors
COLORS = [
    (0, 0, 0), (255, 0, 0), (0, 255, 0), (0, 0, 255),
    (255, 255, 0), (255, 165, 0), (128, 0, 128), (0, 255, 255)
]

# Tetrimino shapes
SHAPES = [
    [[1, 1, 1, 1]],  # I
    [[1, 1], [1, 1]],  # O
    [[0, 1, 0], [1, 1, 1]],  # T
    [[1, 1, 0], [0, 1, 1]],  # S
    [[0, 1, 1], [1, 1, 0]],  # Z
    [[1, 0, 0], [1, 1, 1]],  # L
    [[0, 0, 1], [1, 1, 1]],  # J
]

class Tetrimino:
    def __init__(self):
        self.shape = random.choice(SHAPES)
        self.color = random.choice(COLORS)
        self.x = GRID_WIDTH // 2 - len(self.shape[0]) // 2
        self.y = 0

    def rotate(self):
        self.shape = [list(row) for row in zip(*self.shape[::-1])]

class Game:
    def __init__(self):
        self.board = [[0] * GRID_WIDTH for _ in range(GRID_HEIGHT)]
        self.current_tetrimino = Tetrimino()
        self.score = [0, 0, 0]
        self.player_contributions = [0, 0, 0]
        self.current_player = 0
        self.game_over = False

    def drop_tetrimino(self):
        if not self.game_over:
            self.current_tetrimino.y += 1
            if self.check_collision():
                self.current_tetrimino.y -= 1
                self.place_tetrimino()
                self.clear_lines()
                self.current_tetrimino = Tetrimino()
                if self.check_collision():
                    self.game_over = True

    def check_collision(self):
        for y, row in enumerate(self.current_tetrimino.shape):
            for x, cell in enumerate(row):
                if cell:
                    if (self.current_tetrimino.x + x < 0 or
                        self.current_tetrimino.x + x >= GRID_WIDTH or
                        self.current_tetrimino.y + y >= GRID_HEIGHT or
                        self.board[self.current_tetrimino.y + y][self.current_tetrimino.x + x]):
                        return True
        return False

    def place_tetrimino(self):
        for y, row in enumerate(self.current_tetrimino.shape):
            for x, cell in enumerate(row):
                if cell:
                    self.board[self.current_tetrimino.y + y][self.current_tetrimino.x + x] = self.current_tetrimino.color
        self.score[self.current_player] += 10  # Increment score for the current player
        self.player_contributions[self.current_player] += 10  # Track contributions

    def clear_lines(self):
        lines_cleared = 0
        for i in range(GRID_HEIGHT):
            if all(self.board[i]):
                lines_cleared += 1
                del self.board[i]
                self.board.insert(0, [0] * GRID_WIDTH)
        if lines_cleared > 0:
            for i in range(3):
                self.score[i] += lines_cleared * 100 // 3  # Distribute score evenly

    def switch_player(self):
        self.current_player = (self.current_player + 1) % 3

    def draw(self, screen):
        for y in range(GRID_HEIGHT):
            for x in range(GRID_WIDTH):
                color = self.board[y][x] if self.board[y][x] else (255, 255, 255)
                pygame.draw.rect(screen, color, (x * GRID_SIZE, y * GRID_SIZE, GRID_SIZE, GRID_SIZE), 0)
        for y, row in enumerate(self.current_tetrimino.shape):
            for x, cell in enumerate(row):
                if cell:
                    pygame.draw.rect(screen, self.current_tetrimino.color,
                                     ((self.current_tetrimino.x + x) * GRID_SIZE,
                                      (self.current_tetrimino.y + y) * GRID_SIZE,
                                      GRID_SIZE, GRID_SIZE), 0)

class TetrisGame:
    def __init__(self):
        pygame.init()
        self.screen = pygame.display.set_mode((SCREEN_WIDTH, SCREEN_HEIGHT))
        self.clock = pygame.time.Clock()
        self.game = Game()

    def run(self):
        while not self.game.game_over:
            for event in pygame.event.get():
                if event.type == pygame.QUIT:
                    pygame.quit()
                    return
                if event.type == pygame.KEYDOWN:
                    if event.key == pygame.K_LEFT:
                        self.game.current_tetrimino.x -= 1
                        if self.game.check_collision():
                            self.game.current_tetrimino.x += 1
                    if event.key == pygame.K_RIGHT:
                        self.game.current_tetrimino.x += 1
                        if self.game.check_collision():
                            self.game.current_tetrimino.x -= 1
                    if event.key == pygame.K_DOWN:
                        self.game.drop_tetrimino()
                    if event.key == pygame.K_UP:
                        self.game.current_tetrimino.rotate()
                        if self.game.check_collision():
                            self.game.current_tetrimino.rotate()  # Rotate back

            self.game.drop_tetrimino()
            self.screen.fill((0, 0, 0))
            self.game.draw(self.screen)
            pygame.display.flip()
            self.clock.tick(FPS)

        pygame.quit()

if __name__ == "__main__":
    TetrisGame().run()

