import random

# Constants
SCREEN_WIDTH = 800
SCREEN_HEIGHT = 600
GRID_WIDTH = 10
GRID_HEIGHT = 20
BLOCK_SIZE = 30
FPS = 60

# Colors
COLORS = [
    (0, 0, 0), (255, 0, 0), (0, 255, 0), (0, 0, 255),
    (255, 255, 0), (255, 165, 0), (128, 0, 128), (0, 255, 255)
]

# Tetromino shapes
SHAPES = [
    [[1, 1, 1, 1]],  # I
    [[1, 1], [1, 1]],  # O
    [[0, 1, 0], [1, 1, 1]],  # T
    [[1, 1, 0], [0, 1, 1]],  # S
    [[0, 1, 1], [1, 1, 0]],  # Z
    [[1, 0, 0], [1, 1, 1]],  # L
    [[0, 0, 1], [1, 1, 1]]   # J
]

class Tetromino:
    def __init__(self, shape):
        self.shape = shape
        self.color = COLORS[random.randint(1, len(COLORS) - 1)]
        self.x = GRID_WIDTH // 2 - len(shape[0]) // 2
        self.y = 0

    def rotate(self):
        self.shape = [list(row) for row in zip(*self.shape[::-1])]

class Game:
    def __init__(self):
        self.grid = [[0 for _ in range(GRID_WIDTH)] for _ in range(GRID_HEIGHT)]
        self.score = [0, 0, 0]
        self.current_tetromino = self.new_tetromino()
        self.current_player = 0

    def new_tetromino(self):
        return Tetromino(random.choice(SHAPES))

    def valid_position(self, tetromino):
        for y, row in enumerate(tetromino.shape):
            for x, cell in enumerate(row):
                if cell:
                    if (x + tetromino.x < 0 or x + tetromino.x >= GRID_WIDTH or
                            y + tetromino.y >= GRID_HEIGHT or
                            self.grid[y + tetromino.y][x + tetromino.x]):
                        return False
        return True

    def merge_tetromino(self):
        for y, row in enumerate(self.current_tetromino.shape):
            for x, cell in enumerate(row):
                if cell:
                    self.grid[y + self.current_tetromino.y][x + self.current_tetromino.x] = self.current_player + 1

    def clear_lines(self):
        lines_cleared = 0
        for i in range(GRID_HEIGHT):
            if all(self.grid[i]):
                del self.grid[i]
                self.grid.insert(0, [0 for _ in range(GRID_WIDTH)])
                lines_cleared += 1
        self.score[self.current_player] += lines_cleared

    def switch_player(self):
        self.current_player = (self.current_player + 1) % 3

    def update(self):
        if self.valid_position(self.current_tetromino):
            self.current_tetromino.y += 1
        else:
            self.merge_tetromino()
            self.clear_lines()
            self.current_tetromino = self.new_tetromino()
            if not self.valid_position(self.current_tetromino):
                print("Game Over")
                pygame.quit()

