SCREEN_HEIGHT = 600
GRID_SIZE = 30
BOARD_WIDTH = 10
BOARD_HEIGHT = 20
FPS = 60

# Colors
COLORS = [
    (0, 0, 0), (255, 0, 0), (0, 255, 0), (0, 0, 255),
    (255, 255, 0), (255, 165, 0), (128, 0, 128), (0, 255, 255)
]

# Tetromino shapes
SHAPES = [
    [[1, 1, 1, 1]],  # I
    [[1, 1], [1, 1]],  # O
    [[0, 1, 0], [1, 1, 1]],  # T
    [[1, 1, 0], [0, 1, 1]],  # S
    [[0, 1, 1], [1, 1, 0]],  # Z
    [[1, 0, 0], [1, 1, 1]],  # L
    [[0, 0, 1], [1, 1, 1]]   # J
]

class Tetromino:
    def __init__(self):
        self.shape = random.choice(SHAPES)
        self.color = random.choice(COLORS)
        self.x = BOARD_WIDTH // 2 - len(self.shape[0]) // 2
        self.y = 0

    def rotate(self):
        self.shape = [list(row) for row in zip(*self.shape[::-1])]

class Board:
    def __init__(self):
        self.grid = [[0] * BOARD_WIDTH for _ in range(BOARD_HEIGHT)]
        self.score = 0

    def add_tetromino(self, tetromino):
        for y, row in enumerate(tetromino.shape):
            for x, value in enumerate(row):
                if value:
                    self.grid[tetromino.y + y][tetromino.x + x] = 1

    def clear_lines(self):
        lines_cleared = 0
        for i in range(len(self.grid) - 1, -1, -1):
            if all(self.grid[i]):
                del self.grid[i]
                self.grid.insert(0, [0] * BOARD_WIDTH)
                lines_cleared += 1
        self.score += lines_cleared

class Player:
    def __init__(self, player_id):
        self.id = player_id
        self.board = Board()
        self.tetromino = Tetromino()
        self.contribution = 0

    def drop_tetromino(self):
        self.board.add_tetromino(self.tetromino)
        self.board.clear_lines()
        self.tetromino = Tetromino()

class Game:
    def __init__(self):
        pygame.init()
        self.screen = pygame.display.set_mode((SCREEN_WIDTH, SCREEN_HEIGHT))
        self.clock = pygame.time.Clock()
        self.players = [Player(i) for i in range(3)]
        self.running = True

    def run(self):
        while self.running:
            self.handle_events()
            self.update()
            self.render()
            self.clock.tick(FPS)

    def handle_events(self):
        for event in pygame.event.get():
            if event.type == pygame.QUIT:
                self.running = False

    def update(self):
        for player in self.players:
            player.drop_tetromino()

    def render(self):
        self.screen.fill((0, 0, 0))
        for player in self.players:
            self.draw_board(player)
        pygame.display.flip()

    def draw_board(self, player):
        for y, row in enumerate(player.board.grid):
            for x, value in enumerate(row):
                if value:
                    pygame.draw.rect(self.screen, player.tetromino.color,
                                     (player.tetromino.x * GRID_SIZE, player.tetromino.y * GRID_SIZE, GRID_SIZE, GRID_SIZE))

if __name__ == "__main__":
    game = Game()
    game.run()
    pygame.quit()

import pygame
import random

# Constants
SCREEN_WIDTH = 800
SCREEN_HEIGHT = 600
GRID_SIZE = 30
GRID_WIDTH = SCREEN_WIDTH // GRID_SIZE
GRID_HEIGHT = SCREEN_HEIGHT // GRID_SIZE
FPS = 60

# Colors
COLORS = [
    (0, 0, 0), (255, 0, 0), (0, 255, 0), (0, 0, 255),
    (255, 255, 0), (255, 165, 0), (128, 0, 128), (0, 255, 255)
]

class Piece:
    def __init__(self, shape):
        self.shape = shape
        self.color = random.choice(COLORS)
        self.x = GRID_WIDTH // 2 - len(shape[0]) // 2
        self.y = 0

    def rotate(self):
        self.shape = [list(row) for row in zip(*self.shape[::-1])]

class Tetris:
    def __init__(self):
        self.board = [[0] * GRID_WIDTH for _ in range(GRID_HEIGHT)]
        self.current_piece = self.new_piece()
        self.players = [0, 0, 0]  # Scores for three players
        self.current_player = 0

    def new_piece(self):
        shapes = [
            [[1, 1, 1, 1]],  # I
            [[1, 1], [1, 1]],  # O
            [[0, 1, 0], [1, 1, 1]],  # T
            [[1, 1, 0], [0, 1, 1]],  # S
            [[0, 1, 1], [1, 1, 0]],  # Z
            [[1, 0, 0], [1, 1, 1]],  # L
            [[0, 0, 1], [1, 1, 1]],  # J
        ]
        return Piece(random.choice(shapes))

    def check_collision(self):
        for y, row in enumerate(self.current_piece.shape):
            for x, cell in enumerate(row):
                if cell:
                    if (self.current_piece.x + x < 0 or
                        self.current_piece.x + x >= GRID_WIDTH or
                        self.current_piece.y + y >= GRID_HEIGHT or
                        self.board[self.current_piece.y + y][self.current_piece.x + x]):
                        return True
        return False

    def merge_piece(self):
        for y, row in enumerate(self.current_piece.shape):
            for x, cell in enumerate(row):
                if cell:
                    self.board[self.current_piece.y + y][self.current_piece.x + x] = 1
        self.clear_lines()
        self.current_piece = self.new_piece()

    def clear_lines(self):
        lines_to_clear = [i for i, row in enumerate(self.board) if all(row)]
        for i in lines_to_clear:
            del self.board[i]
            self.board.insert(0, [0] * GRID_WIDTH)
            self.players[self.current_player] += 1  # Increment score for current player

    def switch_player(self):
        self.current_player = (self.current_player + 1) % 3

class Game:
    def __init__(self):
        pygame.init()
        self.screen = pygame.display.set_mode((SCREEN_WIDTH, SCREEN_HEIGHT))
        self.clock = pygame.time.Clock()
        self.tetris = Tetris()
        self.running = True

    def draw_board(self):
        for y in range(GRID_HEIGHT):
            for x in range(GRID_WIDTH):
                if self.tetris.board[y][x]:
                    pygame.draw.rect(self.screen, (255, 255, 255), (x * GRID_SIZE, y * GRID_SIZE, GRID_SIZE, GRID_SIZE))

    def draw_piece(self):
        for y, row in enumerate(self.tetris.current_piece.shape):
            for x, cell in enumerate(row):
                if cell:
                    pygame.draw.rect(self.screen, self.tetris.current_piece.color, 
                                     ((self.tetris.current_piece.x + x) * GRID_SIZE, 
                                      (self.tetris.current_piece.y + y) * GRID_SIZE, 
                                      GRID_SIZE, GRID_SIZE))

    def run(self):
        while self.running:
            self.screen.fill((0, 0, 0))
            self.draw_board()
            self.draw_piece()

            for event in pygame.event.get():
                if event.type == pygame.QUIT:
                    self.running = False
                if event.type == pygame.KEYDOWN:
                    if event.key == pygame.K_LEFT:
                        self.tetris.current_piece.x -= 1
                        if self.tetris.check_collision():
                            self.tetris.current_piece.x += 1
                    if event.key == pygame.K_RIGHT:
                        self.tetris.current_piece.x += 1
                        if self.tetris.check_collision():
                            self.tetris.current_piece.x -= 1
                    if event.key == pygame.K_DOWN:
                        self.tetris.current_piece.y += 1
                        if self.tetris.check_collision():
                            self.tetris.current_piece.y -= 1
                    if event.key == pygame.K_UP:
                        self.tetris.current_piece.rotate()
                        if self.tetris.check_collision():
                            self.tetris.current_piece.rotate()  # Rotate back

            self.tetris.current_piece.y += 1
            if self.tetris.check_collision():
                self.tetris.current_piece.y -= 1
                self.tetris.merge_piece()
                self.tetris.switch_player()

            pygame.display.flip()
            self.clock.tick(FPS)

        pygame.quit()

if __name__ == "__main__":
    Game().run()

