    def add_contribution(self, amount):
        self.contribution += amount

class Tetris:
    def __init__(self):
        self.grid = [[0] * GRID_WIDTH for _ in range(GRID_HEIGHT)]
        self.current_piece = None
        self.current_position = (0, 0)
        self.players = [Player(i) for i in range(3)]
        self.current_player_index = 0

    def new_piece(self):
        self.current_piece = random.choice(SHAPES)
        self.current_position = (0, GRID_WIDTH // 2 - len(self.current_piece[0]) // 2)

    def rotate_piece(self):
        self.current_piece = [list(row) for row in zip(*self.current_piece[::-1])]

    def move_piece(self, dx, dy):
        new_position = (self.current_position[0] + dy, self.current_position[1] + dx)
        if self.valid_position(new_position):
            self.current_position = new_position
        else:
            self.merge_piece()
            self.clear_lines()
            self.new_piece()

    def valid_position(self, position):
        for y, row in enumerate(self.current_piece):
            for x, cell in enumerate(row):
                if cell:
                    grid_x = position[1] + x
                    grid_y = position[0] + y
                    if grid_x < 0 or grid_x >= GRID_WIDTH or grid_y >= GRID_HEIGHT or (grid_y >= 0 and self.grid[grid_y][grid_x]):
                        return False
        return True

    def merge_piece(self):
        for y, row in enumerate(self.current_piece):
            for x, cell in enumerate(row):
                if cell:
                    self.grid[self.current_position[0] + y][self.current_position[1] + x] = self.current_player_index + 1

    def clear_lines(self):
        lines_to_clear = [i for i, row in enumerate(self.grid) if all(row)]
        for i in lines_to_clear:
            del self.grid[i]
            self.grid.insert(0, [0] * GRID_WIDTH)
            self.players[self.current_player_index].add_score(100)

    def switch_player(self):
        self.current_player_index = (self.current_player_index + 1) % 3

    def draw(self, screen):
        for y, row in enumerate(self.grid):
            for x, cell in enumerate(row):
                if cell:
                    pygame.draw.rect(screen, COLORS[cell], (x * GRID_SIZE, y * GRID_SIZE, GRID_SIZE, GRID_SIZE))
        for y, row in enumerate(self.current_piece):
            for x, cell in enumerate(row):
                if cell:
                    pygame.draw.rect(screen, COLORS[self.current_player_index + 1], 
                                     ((self.current_position[1] + x) * GRID_SIZE, 
                                      (self.current_position[0] + y) * GRID_SIZE, 
                                      GRID_SIZE, GRID_SIZE))

