]

# Tetromino shapes
SHAPES = [
    [[1, 1, 1, 1]],  # I
    [[1, 1], [1, 1]],  # O
    [[0, 1, 0], [1, 1, 1]],  # T
    [[1, 1, 0], [0, 1, 1]],  # S
    [[0, 1, 1], [1, 1, 0]],  # Z
    [[1, 0, 0], [1, 1, 1]],  # L
    [[0, 0, 1], [1, 1, 1]],  # J
]

class Tetromino:
    def __init__(self):
        self.shape = random.choice(SHAPES)
        self.color = random.choice(COLORS[1:])
        self.x = GRID_WIDTH // 2 - len(self.shape[0]) // 2
        self.y = 0

    def rotate(self):
        self.shape = [list(row) for row in zip(*self.shape[::-1])]

class Game:
    def __init__(self):
        pygame.init()
        self.screen = pygame.display.set_mode((SCREEN_WIDTH, SCREEN_HEIGHT))
        pygame.display.set_caption("Tetri for WHO")
        self.clock = pygame.time.Clock()
        self.players = [0, 0, 0]
        self.current_tetromino = [Tetromino() for _ in range(3)]
        self.grid = [[0] * GRID_WIDTH for _ in range(GRID_HEIGHT)]
        self.score = [0, 0, 0]
        self.running = True

    def draw_grid(self):
        for y in range(GRID_HEIGHT):
            for x in range(GRID_WIDTH):
                color = COLORS[self.grid[y][x]]
                pygame.draw.rect(self.screen, color, (x * GRID_SIZE, y * GRID_SIZE, GRID_SIZE, GRID_SIZE), 0)

    def draw_tetromino(self, tetromino):
        for y, row in enumerate(tetromino.shape):
            for x, value in enumerate(row):
                if value:
                    pygame.draw.rect(self.screen, tetromino.color, ((tetromino.x + x) * GRID_SIZE, (tetromino.y + y) * GRID_SIZE, GRID_SIZE, GRID_SIZE), 0)

    def check_collision(self, tetromino):
        for y, row in enumerate(tetromino.shape):
            for x, value in enumerate(row):
                if value:
                    if (tetromino.x + x < 0 or tetromino.x + x >= GRID_WIDTH or
                            tetromino.y + y >= GRID_HEIGHT or
                            self.grid[tetromino.y + y][tetromino.x + x]):
                        return True
        return False

    def merge_tetromino(self, tetromino):
        for y, row in enumerate(tetromino.shape):
            for x, value in enumerate(row):
                if value:
                    self.grid[tetromino.y + y][tetromino.x + x] = COLORS.index(tetromino.color)

    def clear_lines(self):
        lines_cleared = 0
        for y in range(GRID_HEIGHT):
            if all(self.grid[y]):
                lines_cleared += 1
                del self.grid[y]
                self.grid.insert(0, [0] * GRID_WIDTH)
        return lines_cleared

    def update_score(self, player_index, lines_cleared):
        self.score[player_index] += lines_cleared * 100

