        while self.running:
            self.screen.fill((255, 255, 255))
            self.draw_grid()
            for i in range(3):
                self.draw_tetromino(self.current_tetromino[i])

            for event in pygame.event.get():
                if event.type == pygame.QUIT:
                    self.running = False

            for i in range(3):
                if not self.check_collision(self.current_tetromino[i]):
                    self.current_tetromino[i].y += 1
                else:
                    self.current_tetromino[i].y -= 1
                    self.merge_tetromino(self.current_tetromino[i])
                    lines_cleared = self.clear_lines()
                    self.update_score(i, lines_cleared)
                    self.current_tetromino[i] = Tetromino()

            pygame.display.flip()
            self.clock.tick(FPS)

        pygame.quit()

if __name__ == "__main__":
