def draw_tetromino(tetromino):
    for y, row in enumerate(tetromino.shape):
        for x, value in enumerate(row):
            if value:
                pygame.draw.rect(screen, tetromino.color, ((tetromino.x + x) * BLOCK_SIZE, (tetromino.y + y) * BLOCK_SIZE, BLOCK_SIZE, BLOCK_SIZE))

def check_collision(tetromino):
    for y, row in enumerate(tetromino.shape):
        for x, value in enumerate(row):
            if value:
                if (tetromino.x + x < 0 or tetromino.x + x >= len(grid[0]) or
                        tetromino.y + y >= len(grid) or grid[tetromino.y + y][tetromino.x + x]):
                    return True
    return False

def merge_tetromino(tetromino):
